import React, { useEffect, useState } from 'react';
import fileService from '../services/fileService';
import { useNavigate } from 'react-router-dom';
function Dashboard(){
  const [file,setFile]=useState(null); const [files,setFiles]=useState([]);
  const [passkey, setPasskey] = useState('');
  const navigate=useNavigate();
  const fetch = async()=>{ try{ const res = await fileService.getMyFiles(); setFiles(res); }catch(e){ console.error(e); } };
  useEffect(()=>{ fetch(); },[]);
  const upload=async(e)=>{ e.preventDefault(); if(!file) return alert('Select file'); if(!passkey) return alert('Enter passkey'); try{ await fileService.uploadFile(file, passkey); alert('Uploaded'); setPasskey(''); setFile(null); (e.target.reset && e.target.reset()); fetch(); }catch(e){ alert(e?.response?.data?.error || 'Upload failed'); } };
  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-100 p-8 flex flex-col items-center">
      <div className="w-full max-w-4xl bg-white rounded-2xl shadow-lg p-8">
        <h2 className="text-3xl font-bold mb-6 text-blue-700">Dashboard</h2>
        <form onSubmit={upload} className="flex flex-col md:flex-row gap-4 mb-8 items-center">
          <input type="file" onChange={e=>setFile(e.target.files[0])} className="border p-2 rounded w-full md:w-auto" />
          <input type="password" placeholder="Passkey" value={passkey} onChange={e=>setPasskey(e.target.value)} className="border p-2 rounded w-full md:w-64" />
          <button className="bg-blue-600 text-white px-6 py-2 rounded-lg shadow hover:bg-blue-700 transition">Upload</button>
        </form>
        <div>
          <h3 className="text-xl font-semibold mb-4 text-gray-700">My Files</h3>
          <div className="overflow-x-auto">
            <table className="min-w-full bg-white rounded-lg shadow border">
              <thead className="bg-blue-100">
                <tr>
                  <th className="py-3 px-4 text-left font-semibold text-gray-700">ID</th>
                  <th className="py-3 px-4 text-left font-semibold text-gray-700">Name</th>
                  <th className="py-3 px-4 text-left font-semibold text-gray-700">Uploaded</th>
                  <th className="py-3 px-4 text-left font-semibold text-gray-700">Actions</th>
                </tr>
              </thead>
              <tbody>
                {files.map(f => (
                  <tr key={f.id} className="border-t hover:bg-blue-50 transition">
                    <td className="py-2 px-4">{f.id}</td>
                    <td className="py-2 px-4">{f.originalname}</td>
                    <td className="py-2 px-4">{new Date(f.uploaded_at).toLocaleString()}</td>
                    <td className="py-2 px-4 flex gap-2">
                      <button onClick={() => navigate('/view/' + f.id)} className="bg-blue-500 text-white px-3 py-1 rounded-lg shadow hover:bg-blue-600 transition">View</button>
                      <button onClick={() => navigate('/grant-access/' + f.id)} className="bg-green-500 text-white px-3 py-1 rounded-lg shadow hover:bg-green-600 transition">Grant</button>
                      <button onClick={async () => { await fileService.deleteFile(f.id); fetch(); }} className="bg-red-500 text-white px-3 py-1 rounded-lg shadow hover:bg-red-600 transition">Delete</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}
export default Dashboard;
